local _yc = 0

local function set(inst, prop, value)
    local ok = pcall(function() inst[prop] = value end)
    if not ok and sethiddenproperty then
        pcall(sethiddenproperty, inst, prop, value)
    end
    _yc = _yc + 1
    if _yc % 150 == 0 then task.wait() end
end

local function setParent(inst, parent)
    pcall(function() inst.Parent = parent end)
end

local function setAttr(inst, name, value)
    pcall(function() inst:SetAttribute(name, value) end)
end

